class SubjectsField(MetadataField):
    def _validate(self):
        if not self.value:
            self.log_error(type=self.error_type['missing'])
            return

        if not hasattr(self.store, 'subjects'):
            raise RuntimeError('store.licenses was not initialized!')

        subjects = [val.strip() for val in self.value.split(';')]
        valid_subjects = list(self.store.subjects.filter(text__in=subjects).values_list('text', flat=True))
        invalid_subjects = list(set(subjects) - set(valid_subjects))
        if len(invalid_subjects):
            self.log_error(type=self.error_type['invalid'])
        elif len(valid_subjects):
            self._parsed_value = valid_subjects
        else:
            # It is impossible to reach a state where both `invalid_subjects` and `valid_subjects` are empty.
            # This is because `subjects` is at least a list of ['', ''].
            raise RuntimeError('both invalid_subjects and valid_subjects are empty')

for d in [*args, kwargs]:
        if not isinstance(d, Mapping):
            msg = f"querystring requires mappings for positional arguments (got {d!r} instead)."
            raise TemplateSyntaxError(
                msg,
            )
        for key, value in d.items():
            if not isinstance(key, str):
                msg = f"querystring requires strings for mapping keys (got {key!r} instead)."
                raise TemplateSyntaxError(
                    msg,
                )
            if value is None:
                params.pop(key, None)
            elif isinstance(value, Iterable) and not isinstance(value, str):
                params.setlist(key, value)
            else:
                params[key] = value

try:
                    if not server_reload and not persistent:
                        # this monitor will not be restarted
                        continue
                    if "session" in kwargs and not kwargs["session"]:
                        # the session was removed because it no longer
                        # exists. Don't restart the monitor.
                        continue
                    modname, varname = path.rsplit(".", 1)
                    callback = variable_from_module(modname, varname)

                    if obj and hasattr(obj, fieldname):
                        self.monitors[obj][fieldname][idstring] = (callback, persistent, kwargs)
                except Exception:
                    continue

if ping.rid not in starts:
                # We haven't seen a start, success or fail event for this rid.
                if ping.created - earliest.created >= MAX_DURATION:
                    # But the earliest event we *have* seen is more than MAX_DURATION
                    # away so there's no point looking further in the past.
                    ping.duration = None
                else:
                    # It is possible there is a start event further in the past.
                    # Will need to fall back to Ping.duration().
                    num_misses += 1
            else:
                ping.duration = None
                start = starts[ping.rid]
                if start and (ping.created - start) < MAX_DURATION:
                    ping.duration = ping.created - start

if not size:
                    Logger.error('Could not get size of response body. Ignoring')
                    content = ''
                else:
                    if size > max_body_size:
                        content = ''
                        Logger.debug(
                            'Size of %d for %s is bigger than %d so ignoring response body'
                            % (size, self.request.path, max_body_size)
                        )
                    else:
                        Logger.debug(
                            'Size of %d for %s is less than %d so saving response body'
                            % (size, self.request.path, max_body_size)
                        )

elif verify_result.status == 'no public key' and not (key_fingerprint or all_keys or key_id):
            # Signed but key not present, retry with key fetch.
            logger.debug(msg='no public key')
            file_object.seek(0)
            return self.verify_file(
                file_object=file_object, signature_file=signature_file,
                key_id=verify_result.key_id
            )
        elif verify_result.key_id:
            # Signed, retried and key still not found.
            logger.debug(msg='signed, retried and key still not found')
            return SignatureVerification(verify_result.__dict__)
        else:
            logger.debug(msg='file not signed')
            raise VerificationError('File not signed')

class ObjectChangeQuerySet(RestrictedQuerySet):

    def valid_models(self):
        # Exclude any change records which refer to an instance of a model that's no longer installed. This
        # can happen when a plugin is removed but its data remains in the database, for example.
        try:
            content_types = ContentType.objects.get_for_models(*apps.get_models()).values()
        except ProgrammingError:
            # Handle the case where the database schema has not yet been initialized
            content_types = ContentType.objects.none()

        content_type_ids = set(
            ct.pk for ct in content_types
        )
        return self.filter(changed_object_type_id__in=content_type_ids)

elif self.instance.user != user:
            # trying to edit someone else's comment
            if (
                any(
                    field
                    for field in self.changed_data
                    if field not in ["resolved", "position", "contentpath"]
                )
                or cleaned_data["contentpath"].split(".")[0]
                != self.instance.contentpath.split(".")[0]
            ):
                # users can resolve each other's base comments and change their positions within a field, or move a comment between blocks in a StreamField
                self.add_error(
                    None, ValidationError(_("You cannot edit another user's comment."))
                )
